############################################################ # PG Setup Code ############################################################ $n = random(2015, 2030); $p = 0.34*($n - 2010) + 28.3; Context()->variables->are(n => 'Real'); $proposed_solution = (random(0,1)) ? $n : $n + non_zero_random(-1, 3); $left = Formula($p); $right = Formula("0.34(n - 2010) + 28.3"); Context("LimitedNumeric"); $lefteval = Real($left->eval(n => $proposed_solution)); $righteval = Real($right->eval(n => $proposed_solution)); $dropdown = DropDown( ["Yes, it is a solution.", "No, it is not a solution."], ($lefteval == $righteval) ? 0 : 1, showInStatic => 0 );
############################################################ # Body ############################################################
BEGIN_PGML Since the year 2010, the percent of wealth in the United States that is held by the wealthiest 1% has followed the formula [`p=0.34(n-2010)+28.3`] where [`n`] is the year. If you want to know when the top 1% held [$p]% of the wealth, you have the equation [`[$left]=[$right]\text{.}`] Does this happen in the year [`[$proposed_solution]\text{?}`]
>> [@DataTable( [ [PGML('[`[$left->TeX]`]'), PGML('[`=`]'), PGML('[`[$right->TeX]`]'), ], [PGML('[`[$lefteval->TeX]`]'), PGML('[`\wonder{=}`]'), PGML('[_]{$righteval}{3}'), ], ], align => 'rcl', valign => 'middle',);@]* <<
[_]{$dropdown}{5}
END_PGML
